import React, { useState, useEffect, useMemo } from 'react';
import { GraduationCap, Search, User, LogOut, Menu, X, Filter, Grid, List, Award, RefreshCw, Play, Bookmark } from 'lucide-react';
import CourseCard from './components/CourseCard.jsx';
import { CourseCardSkeleton } from './components/LoadingSpinner.jsx';
import AdvancedSearchBar from './components/AdvancedSearchBar.jsx';
import QuickStats from './components/QuickStats.jsx';
import PaymentModal from './components/PaymentModal.jsx';
import { sortCourses } from './utils/courseUtils';
import { useDebounce } from './hooks/useDebounce';
import { validateSearchQuery } from './utils/validation';
import useCourseStore from './store/courseStore';
import useAuthStore from './store/authStore';
import { useToast } from './components/Toast.jsx';

const Course = ({ courses }) => {
  const { showToast } = useToast();
  const { enrollInCourse, getStats } = useCourseStore();
  const { user } = useAuthStore();

  // Auto-convert Dropbox URLs
  const processedCourses = useMemo(() => 
    courses.map(course => ({
      ...course,
      videoUrl: course.videoUrl?.includes('dropbox.com') && course.videoUrl?.includes('dl=0') 
        ? course.videoUrl.replace('dl=0', 'raw=1')
        : course.videoUrl
    })), [courses]
  );

  const [filteredCourses, setFilteredCourses] = useState([]);
  const [isLoading, setIsLoading] = useState(false);

  const [activeFilter, setActiveFilter] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('rating');
  const [showMobileMenu, setShowMobileMenu] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [paymentCourse, setPaymentCourse] = useState(null);
  const [username] = useState('Instructor');
  const [viewMode, setViewMode] = useState('grid');
  const [showAdvancedFilters, setShowAdvancedFilters] = useState(false);
  const [priceRange, setPriceRange] = useState([0, 200]);
  const [ratingFilter, setRatingFilter] = useState(0);
  const [recentSearches, setRecentSearches] = useState([]);

  const debouncedSearchTerm = useDebounce(searchTerm, 300);
  const stats = getStats();

  const getVideoUrl = (url) => {
    if (!url) return null;
    if (url.includes('dropbox.com')) {
      return url.replace('dl=0', 'dl=1').replace('&amp;', '&');
    }
    if (url.includes('youtube.com/watch?v=')) {
      return url.replace('watch?v=', 'embed/');
    }
    return url;
  };

  // Memoized filtering and sorting
  const filteredAndSortedCourses = useMemo(() => {
    setIsLoading(true);

    let filtered = processedCourses.filter(course => {
      const matchesFilter = activeFilter === 'all' || course.cat === activeFilter;
      const matchesSearch = !debouncedSearchTerm || 
        course.title.toLowerCase().includes(debouncedSearchTerm.toLowerCase()) || 
        course.instructor.toLowerCase().includes(debouncedSearchTerm.toLowerCase()) ||
        course.desc.toLowerCase().includes(debouncedSearchTerm.toLowerCase());
      const matchesPrice = course.price >= priceRange[0] && course.price <= priceRange[1];
      const matchesRating = parseFloat(course.rating) >= ratingFilter;
      return matchesFilter && matchesSearch && matchesPrice && matchesRating;
    });

    const sorted = sortCourses(filtered, sortBy);

    setTimeout(() => setIsLoading(false), 100); // Small delay for smooth UX
    return sorted;
  }, [processedCourses, activeFilter, debouncedSearchTerm, sortBy, priceRange, ratingFilter]);

  useEffect(() => {
    setFilteredCourses(filteredAndSortedCourses);
  }, [filteredAndSortedCourses]);

  const handleEnrollInCourse = (course) => {
    const { enrolledCourses } = useCourseStore.getState();
    if (enrolledCourses.includes(course.id)) {
      showToast('You are already enrolled in this course', 'info');
      return;
    }
    setPaymentCourse(course);
  };

  const handlePaymentSuccess = (course, email) => {
    const success = enrollInCourse(course.id);
    if (success) {
      showToast(`Payment successful! Welcome to ${course.title}`, 'success', {
        title: 'Enrollment Complete'
      });

      // Simulate sending confirmation email
      setTimeout(() => {
        showToast(`Confirmation email sent to ${email}`, 'info', {
          title: 'Email Sent'
        });
      }, 1000);

      // Show course access message
      setTimeout(() => {
        showToast('You can now access your course content!', 'success', {
          title: 'Course Access Granted'
        });
      }, 2000);
    }
  };

  const handleSearch = (query) => {
    if (validateSearchQuery(query)) {
      setSearchTerm(query);
    }
  };

  const handleRecentSearch = (query) => {
    setRecentSearches(prev => {
      const filtered = prev.filter(search => search !== query);
      return [query, ...filtered].slice(0, 5);
    });
  };

  const clearAllFilters = () => {
    setActiveFilter('all');
    setSearchTerm('');
    setShowAdvancedFilters(false);
    setPriceRange([0, 200]);
    setRatingFilter(0);
    showToast('All filters cleared', 'info');
  };

  // Course suggestions for search
  const courseSuggestions = useMemo(() => 
    processedCourses.map(course => course.title), 
    [processedCourses]
  );

  const Modal = ({ course, onClose }) => (
    <div className="fixed inset-0 flex items-center justify-center bg-black/50 z-50 p-4">
      <div className="bg-white rounded-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
        <div className="relative">
          <img className="w-full h-48 sm:h-64 object-cover" src={course.img} alt={course.title} />
          <button onClick={onClose} className="absolute top-4 right-4 bg-white/90 text-gray-700 w-8 h-8 rounded-full flex items-center justify-center hover:bg-white transition">
            <X className="w-4 h-4" />
          </button>
        </div>
        <div className="p-6 sm:p-8">
          <div className="flex flex-col sm:flex-row justify-between items-start mb-4 gap-2">
            <h2 className="text-xl sm:text-2xl font-bold text-gray-900">{course.title}</h2>
            <span className="text-xl sm:text-2xl font-bold text-blue-600">₹{course.price.toLocaleString()}</span>
          </div>
          <p className="text-gray-600 mb-6">{course.desc}</p>

          {course.videoUrl && (
            <div className="mb-6">
              <h3 className="text-lg font-semibold mb-3">Course Preview</h3>
              {course.videoUrl.includes('youtube.com') || course.videoUrl.includes('youtu.be') ? (
                <iframe 
                  className="w-full h-64 rounded-lg"
                  src={course.videoUrl.replace('watch?v=', 'embed/')}
                  frameBorder="0"
                  allowFullScreen
                />
              ) : (
                <video 
                  className="w-full h-64 rounded-lg bg-black"
                  controls
                  preload="metadata"
                >
                  <source src={course.videoUrl.replace(/dl=0/g, 'raw=1').replace(/&amp;/g, '&')} type="video/mp4" />
                  Your browser does not support the video tag.
                </video>
              )}
            </div>
          )}

          <div className="grid grid-cols-2 gap-4 mb-6">
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Instructor</div>
              <div className="font-semibold text-gray-900">{course.instructor}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Duration</div>
              <div className="font-semibold text-gray-900">{course.time}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Level</div>
              <div className="font-semibold text-gray-900">{course.level}</div>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg">
              <div className="text-gray-500 text-sm">Students</div>
              <div className="font-semibold text-gray-900">{course.enrolled.toLocaleString()}</div>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row space-y-2 sm:space-y-0 sm:space-x-4">
            <button className="flex-1 bg-green-600 hover:bg-green-700 text-white font-semibold py-3 px-6 rounded-lg transition">
              <Play className="w-4 h-4 inline mr-2" />Preview as Instructor
            </button>
            <button className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-6 py-3 rounded-lg transition">
              <Bookmark className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50" style={{fontFamily: 'Inter, sans-serif'}}>

      <section className="pt-16 pb-16 bg-gradient-to-br from-blue-50 via-white to-purple-50 relative overflow-hidden">
        <div className="absolute inset-0 bg-grid-pattern opacity-5"></div>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center relative">
          <div className="mb-8">
            <div className="inline-flex items-center bg-blue-100 text-blue-700 px-4 py-2 rounded-full text-sm font-medium mb-4">
              <Award className="w-4 h-4 mr-2" />
              #1 Learning Platform
            </div>
            <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold mb-6 text-gray-900">
              Learn Without <span className="bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">Limits</span>
            </h1>
            <p className="text-lg sm:text-xl mb-8 text-gray-600 max-w-3xl mx-auto leading-relaxed">
              Start, switch, or advance your career with {courses.length} courses, Professional Certificates, and degrees from world-class universities and companies.
            </p>
          </div>

          <QuickStats courses={courses} />

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-4 rounded-xl font-semibold text-lg hover:from-blue-700 hover:to-purple-700 transition-all duration-200 transform hover:scale-105 shadow-lg">
              Start Learning Today
            </button>
            <button className="border-2 border-gray-300 text-gray-700 px-8 py-4 rounded-xl font-semibold text-lg hover:border-blue-600 hover:text-blue-600 transition-all duration-200">
              Watch Demo
            </button>
          </div>
        </div>
      </section>

      <div className="bg-white border-b border-gray-200 py-6">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
            <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 w-full lg:w-auto">
              <div className="flex flex-wrap gap-2">
                {['all', 'development', 'ai', 'design', 'business'].map(filter => (
                  <button 
                    key={filter}
                    onClick={() => setActiveFilter(filter)}
                    className={`px-4 py-2 rounded-xl text-sm font-medium transition-all duration-200 ${
                      activeFilter === filter 
                        ? 'bg-gradient-to-r from-blue-600 to-purple-600 text-white shadow-lg transform scale-105' 
                        : 'text-gray-700 bg-gray-100 hover:bg-gray-200 hover:scale-105'
                    }`}
                  >
                    {filter === 'all' ? 'All Courses' : filter === 'ai' ? 'AI & ML' : filter.charAt(0).toUpperCase() + filter.slice(1)}
                  </button>
                ))}
              </div>

              <button
                onClick={() => setShowAdvancedFilters(!showAdvancedFilters)}
                className="flex items-center px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-xl hover:bg-gray-200 transition-colors"
              >
                <Filter className="w-4 h-4 mr-2" />
                Advanced Filters
              </button>
            </div>

            <div className="flex items-center gap-4 w-full lg:w-auto">
              <div className="flex items-center bg-gray-100 rounded-xl p-1">
                <button
                  onClick={() => setViewMode('grid')}
                  className={`p-2 rounded-lg transition-colors ${
                    viewMode === 'grid' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-600'
                  }`}
                >
                  <Grid className="w-4 h-4" />
                </button>
                <button
                  onClick={() => setViewMode('list')}
                  className={`p-2 rounded-lg transition-colors ${
                    viewMode === 'list' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-600'
                  }`}
                >
                  <List className="w-4 h-4" />
                </button>
              </div>

              <select 
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
                className="bg-white border border-gray-300 rounded-xl px-4 py-2 text-gray-700 focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm min-w-[160px]"
              >
                <option value="rating">⭐ Highest Rated</option>
                <option value="price">💰 Price: Low to High</option>
                <option value="enrolled">🔥 Most Popular</option>
              </select>
            </div>
          </div>

          {showAdvancedFilters && (
            <div className="mt-6 p-6 bg-gray-50 rounded-2xl border border-gray-200">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Price Range</label>
                  <div className="flex items-center space-x-4">
                    <input
                      type="range"
                      min="0"
                      max="200"
                      value={priceRange[1]}
                      onChange={(e) => setPriceRange([0, parseInt(e.target.value)])}
                      className="flex-1"
                    />
                    <span className="text-sm font-medium text-gray-600">₹0 - ₹{priceRange[1]}</span>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Minimum Rating</label>
                  <select
                    value={ratingFilter}
                    onChange={(e) => setRatingFilter(parseFloat(e.target.value))}
                    className="w-full bg-white border border-gray-300 rounded-lg px-3 py-2 text-sm"
                  >
                    <option value={0}>Any Rating</option>
                    <option value={4.5}>4.5+ Stars</option>
                    <option value={4.0}>4.0+ Stars</option>
                    <option value={3.5}>3.5+ Stars</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Quick Filters</label>
                  <div className="flex flex-wrap gap-2">
                    <button className="px-3 py-1 text-xs bg-white border border-gray-300 rounded-full hover:bg-gray-50">
                      Free Courses
                    </button>
                    <button className="px-3 py-1 text-xs bg-white border border-gray-300 rounded-full hover:bg-gray-50">
                      With Certificate
                    </button>
                    <button className="px-3 py-1 text-xs bg-white border border-gray-300 rounded-full hover:bg-gray-50">
                      Beginner Friendly
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 sm:py-12">
        {isLoading ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {Array.from({ length: 6 }).map((_, index) => (
              <CourseCardSkeleton key={index} />
            ))}
          </div>
        ) : (
          <div className={`${viewMode === 'grid' 
            ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6' 
            : 'space-y-6'
          }`}>
            {filteredCourses.map(course => (
              <CourseCard 
                key={course.id} 
                course={course} 
                viewMode={viewMode}
                onEnroll={handleEnrollInCourse}
                onPreview={setSelectedCourse}
              />
            ))}
          </div>
        )}

        {filteredCourses.length === 0 && (
          <div className="text-center py-16">
            <div className="w-24 h-24 mx-auto mb-6 bg-gray-100 rounded-full flex items-center justify-center">
              <Search className="w-12 h-12 text-gray-400" />
            </div>
            <h3 className="text-xl font-semibold text-gray-900 mb-2">No courses found</h3>
            <p className="text-gray-600 mb-6">Try adjusting your search criteria or filters</p>
            <button 
              onClick={clearAllFilters}
              className="bg-blue-600 text-white px-6 py-3 rounded-xl font-medium hover:bg-blue-700 transition-colors"
            >
              Clear All Filters
            </button>
          </div>
        )}
      </div>

      {selectedCourse && (
        <Modal course={selectedCourse} onClose={() => setSelectedCourse(null)} />
      )}

      {paymentCourse && (
        <PaymentModal 
          course={paymentCourse} 
          onClose={() => setPaymentCourse(null)}
          onPaymentSuccess={handlePaymentSuccess}
        />
      )}
    </div>
  );
};

export default Course;
